const runRDSImport = async () => {
  try {
    console.log('Connecting to AWS RDS Database using server/.env credentials...');
    console.log(`Executing ${embeddedQueries.length} embedded safe import queries on AWS RDS...`);
    let successCount = 0;
    for (const query of embeddedQueries) {
      if (!query) continue;
      try {
        await pool.query(query);
        successCount++;
      } catch (err) {
        console.warn(`Warning on query: ${err.message}`);
      }
    }
    console.log(`✅ Successfully executed safe import on AWS RDS (${successCount} queries completed).`);
    process.exit(0);
  } catch (err) {
    console.error('❌ RDS Import failed:', err);
    process.exit(1);
  }
};

runRDSImport();
